import React, { useState } from 'react';
import { ChevronLeft } from 'lucide-react';
import { useCurrency } from '../context/CurrencyContext';

export default function LoanApplicationScreen({ onBack, onSubmit }) {
  const { formatAmount } = useCurrency();
  const [amount, setAmount] = useState('');

  return (
    <div className="flex flex-col bg-white animate-in slide-in-from-right duration-300">
      {/* Header */}
      <div className="flex items-center px-6 py-4 sticky top-0 bg-white z-10">
        <button onClick={onBack} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
          <ChevronLeft className="w-6 h-6 text-gray-800" />
        </button>
        <h1 className="text-xl font-black text-gray-900 ml-4">Apply for Loan</h1>
      </div>

      <div className="p-6 flex-1">
        <label className="text-sm font-bold text-gray-700 ml-1">Loan Amount</label>
        <div className="relative mt-2">
          <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">{formatAmount(0).replace(/\d/g,'')}</span>
          <input 
            type="number" 
            value={amount}
            onChange={e => setAmount(e.target.value)}
            placeholder="0.00"
            className="w-full p-4 pl-12 rounded-2xl bg-gray-50 border border-gray-100 outline-none focus:border-[#00875A] text-lg font-bold" 
          />
        </div>

        <button 
          onClick={() => onSubmit(parseFloat(amount))}
          className="w-full py-4 mt-6 rounded-2xl font-black text-white bg-[#00875A] shadow-lg active:scale-[0.98] transition-all"
        >
          Submit Application
        </button>
      </div>
    </div>
  );
}
